mapper.insert:

    select pj_seq.nextval from dual


DECLARE
    v_parent_rgt INTEGER;
BEGIN



            SELECT prj_rgt INTO v_parent_rgt FROM project WHERE id = #{prjParId};

            UPDATE project SET prj_lft = prj_lft + 2 WHERE prj_lft >= v_parent_rgt;
            UPDATE project SET prj_rgt = prj_rgt + 2 WHERE prj_rgt >= v_parent_rgt;

            #{prjLft} := v_parent_rgt;
            #{prjRgt} := v_parent_rgt + 1;




            SELECT NVL(MAX(prj_rgt), 0) + 1 INTO v_parent_rgt FROM project;
            #{prjLft} := v_parent_rgt;
            #{prjRgt} := v_parent_rgt + 1;



    -- 프로젝트 삽입
    INSERT INTO project (
        id, biz_no, prj_par_id, prj_root_id, prj_name, 
        prj_desc, prj_identifier, prj_status_cd, prj_lft, prj_rgt, user_id
    ) VALUES (
        #{id}, #{bizNo}, #{prjParId}, #{prjRootId}, #{prjName}, 
        #{prjDesc}, #{prjIdentifier}, '01PROSTAT', #{prjLft}, #{prjRgt}, #{userId}
    );

    -- 모듈 삽입
    INSERT INTO enabled_modules (ena_id, prj_id, ena_name_cd)
    VALUES (en_mod_seq.nextval, #{id}, #{enaNameCd});

END;
